// APP
// ══════════════════════════════════════════════════════════════════════════════
function FacturationModule({ settings, batSupports=[], setBatSupports }) {
  const [tab, setTab] = useState("invoices");
  const [invoices, setInvoices] = useLocalStorage("ttb_invoices", defaultInvoices);
  const [clients,  setClients]  = useLocalStorage("ttb_clients",  defaultClients);
  const [importMsg, setImportMsg] = useState(null);
  const [saveFlash, setSaveFlash] = useState(false);
  const importRef = useRef();

  // Flash visuel à chaque sauvegarde
  const wrapSet = (setter) => (val) => { setter(val); setSaveFlash(true); setTimeout(()=>setSaveFlash(false), 1500); };

  const accent = settings.accentColor || "#F5C518";

  // ── Export données facturation
  const handleExport = () => {
    const data = { version:"1.1", exportedAt:new Date().toISOString(), invoices, clients, batSupports };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type:"application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url; a.download = `ttb-devis-${new Date().toISOString().slice(0,10)}.json`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  // ── Import données facturation
  const handleImport = (e) => {
    const file = e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const data = JSON.parse(ev.target.result);
        if (data.invoices)     { setInvoices(data.invoices); }
        if (data.clients)      { setClients(data.clients);  }
        if (data.batSupports && setBatSupports) { setBatSupports(data.batSupports); }
        setSaveFlash(true); setTimeout(()=>setSaveFlash(false), 1500);
        setImportMsg({ type:"success", text:`✓ Import réussi — ${(data.invoices||[]).length} documents, ${(data.clients||[]).length} clients${data.batSupports?.length ? ", " + data.batSupports.length + " article(s) BAT" : ""}.` });
        setTimeout(() => setImportMsg(null), 3500);
      } catch {
        setImportMsg({ type:"error", text:"Erreur de lecture — fichier corrompu." });
        setTimeout(() => setImportMsg(null), 3500);
      }
    };
    reader.readAsText(file); e.target.value = "";
  };

  const tabs = [
    { id:"invoices", label:"Devis / Factures" },
    { id:"clients",  label:"Clients" },
  ];

  return (
    <div style={{ color:"#EEF0F7", fontFamily:"'DM Sans','Segoe UI',sans-serif" }}>
      <input ref={importRef} type="file" accept=".json" style={{ display:"none" }} onChange={handleImport} />

      {/* Toast */}
      {importMsg && (
        <div style={{ position:"fixed", top:72, left:"50%", transform:"translateX(-50%)", zIndex:9999,
          padding:"12px 24px", borderRadius:10, fontWeight:700, fontSize:13,
          background: importMsg.type==="success" ? "#1a3a2a" : "#3a1a1a",
          color: importMsg.type==="success" ? "#4ade80" : "#f87171",
          border:`1px solid ${importMsg.type==="success"?"#166534":"#991b1b"}`,
          boxShadow:"0 8px 32px rgba(0,0,0,.4)" }}>
          {importMsg.text}
        </div>
      )}

      {/* Indicateur sauvegarde */}
      {saveFlash && (
        <div style={{ position:"fixed", bottom:20, right:20, zIndex:9999, background:"#0a1a0f", border:"1px solid #22C55E",
          borderRadius:8, padding:"8px 16px", color:"#4ade80", fontSize:12, fontWeight:700,
          display:"flex", alignItems:"center", gap:6, boxShadow:"0 4px 20px rgba(0,0,0,.4)" }}>
          <svg width={12} height={12} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M20 6L9 17l-5-5"/></svg>
          Sauvegardé
        </div>
      )}

      {/* Onglets internes */}
      <div style={{ display:"flex", alignItems:"center", gap:4, marginBottom:20, borderBottom:"1px solid #23253A", paddingBottom:12 }}>
        {tabs.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            style={{ padding:"6px 18px", borderRadius:7, border:"none", cursor:"pointer",
              fontFamily:"inherit", fontWeight:600, fontSize:13,
              background: tab===t.id ? accent : "#1C1F2A",
              color: tab===t.id ? "#111318" : "#7A7F9A" }}>
            {t.label}
          </button>
        ))}
        <div style={{ marginLeft:"auto", display:"flex", gap:6 }}>
          <button onClick={handleExport} title="Exporter les données (.json)"
            style={{ padding:"6px 14px", borderRadius:7, border:"1px solid #23253A",
              background:"#1C1F2A", color:"#7A7F9A", cursor:"pointer",
              fontFamily:"inherit", fontSize:12, display:"flex", alignItems:"center", gap:6 }}>
            <svg width={13} height={13} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4 M7 10l5 5 5-5 M12 15V3"/></svg>
            Exporter
          </button>
          <button onClick={() => importRef.current.click()} title="Importer"
            style={{ padding:"6px 14px", borderRadius:7, border:"1px solid #23253A",
              background:"#1C1F2A", color:"#7A7F9A", cursor:"pointer",
              fontFamily:"inherit", fontSize:12, display:"flex", alignItems:"center", gap:6 }}>
            <svg width={13} height={13} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4 M17 8l-5-5-5 5 M12 3v12"/></svg>
            Importer
          </button>
        </div>
      </div>

      {tab === "invoices" && <InvoicesTab invoices={invoices} setInvoices={wrapSet(setInvoices)} clients={clients} settings={settings} />}
      {tab === "clients"  && <ClientsTab  clients={clients}   setClients={wrapSet(setClients)}   settings={settings} />}
    </div>
  );
}


